import sys

def cmd_count(text):
    words = text.split()
    print(f'Word count: {len(words)}')

def cmd_reverse(text):
    print(text[::-1])

def cmd_upper(text):
    print(text.upper())

COMMANDS = {
    'count': cmd_count,
    'reverse': cmd_reverse,
    'upper': cmd_upper,
}

if __name__ == '__main__':
    if len(sys.argv) < 3:
        print('Usage: python3 tools.py <command> <text>')
        print(f'Commands: {", ".join(COMMANDS)}')
        sys.exit(1)

    cmd = sys.argv[1]
    text = ' '.join(sys.argv[2:])

    if cmd not in COMMANDS:
        print(f'Unknown command: {cmd}')
        sys.exit(1)

    COMMANDS[cmd](text)
    sys.exit(0)
